mapper.select:
SELECT id, location, temperature, humidity, timestamp FROM sensor_data
location = #{location}
AND timestamp >= NOW() - (#{hours}::int * INTERVAL '1 hour')
ORDER BY timestamp DESC LIMIT #{limit}

SELECT time_bucket(#{bucket}::interval, timestamp) AS bucket, location, ROUND(AVG(temperature)::numeric, 2) AS avg_temp, ROUND(MIN(temperature)::numeric, 2) AS min_temp, ROUND(MAX(temperature)::numeric, 2) AS max_temp, ROUND(AVG(humidity)::numeric, 2) AS avg_humidity, COUNT(*) AS sample_count FROM sensor_data WHERE timestamp >= NOW() - (#{hours}::int * INTERVAL '1 hour')
AND location = #{location}
GROUP BY bucket, location ORDER BY bucket ASC

SELECT bucket, location, ROUND(avg_temp::numeric, 2) AS avg_temp, ROUND(min_temp::numeric, 2) AS min_temp, ROUND(max_temp::numeric, 2) AS max_temp, ROUND(avg_humidity::numeric, 2) AS avg_humidity, sample_count FROM sensor_hourly_avg WHERE bucket >= NOW() - (#{hours}::int * INTERVAL '1 hour')
AND location = #{location}
ORDER BY bucket ASC

SELECT bucket, location, ROUND(avg_temp::numeric, 2) AS avg_temp, ROUND(min_temp::numeric, 2) AS min_temp, ROUND(max_temp::numeric, 2) AS max_temp, ROUND(avg_humidity::numeric, 2) AS avg_humidity, sample_count FROM sensor_daily_avg WHERE bucket >= NOW() - (#{days}::int * INTERVAL '1 day')
AND location = #{location}
ORDER BY bucket ASC
